# Query Wikimedia API for a batch of key image files
# Using Python-style URL encoding — we'll use curl with proper User-Agent

check_image() {
  local filename="$1"
  local encoded=$(node -e "console.log(encodeURIComponent('$filename'))")
  local result=$(curl -s -A "HistoriaApp/1.0 (research; contact@historia.app)" \
    "https://commons.wikimedia.org/w/api.php?action=query&titles=File:${encoded}&prop=imageinfo&iiprop=url%7Cmime%7Cextmetadata&iiurlwidth=500&format=json" 2>/dev/null)
  echo "=== $filename ==="
  echo "$result" | node -e "
    const chunks=[];
    process.stdin.on('data',d=>chunks.push(d));
    process.stdin.on('end',()=>{
      const data=JSON.parse(chunks.join(''));
      const pages=data.query && data.query.pages;
      if(!pages) { console.log('ERROR: no pages'); return; }
      const page=Object.values(pages)[0];
      if(!page) { console.log('ERROR: empty'); return; }
      if(page.missing !== undefined) { console.log('MISSING'); return; }
      const ii = page.imageinfo && page.imageinfo[0];
      if(!ii) { console.log('NO IMAGEINFO'); return; }
      console.log('URL:', ii.thumburl || 'no-thumb');
      const lic = ii.extmetadata && ii.extmetadata.LicenseShortName;
      console.log('License:', lic ? lic.value : 'unknown');
    });
  " 2>/dev/null
}

