# Search Wikimedia for the right filenames using the search API
search_wikimedia() {
  local query="$1"
  local encoded=$(node -e "console.log(encodeURIComponent('$1'))")
  local result=$(curl -s -A "HistoriaApp/1.0" \
    "https://commons.wikimedia.org/w/api.php?action=query&list=search&srsearch=${encoded}&srnamespace=6&srlimit=5&format=json" 2>/dev/null)
  echo "=== SEARCH: $query ==="
  echo "$result" | node -e "
    const chunks=[];
    process.stdin.on('data',d=>chunks.push(d));
    process.stdin.on('end',()=>{
      const data=JSON.parse(chunks.join(''));
      const hits = data.query && data.query.search || [];
      hits.forEach(h=>console.log(h.title));
    });
  " 2>/dev/null
}

